mapper.select:
SELECT f.id, f.user_id AS userId, f.follow_type AS followType, f.follow_id AS followId, f.create_time AS createTime, h.name AS hospitalName, h.level AS hospitalLevel, h.image AS hospitalImage, h.intro AS hospitalIntro, d.name AS doctorName, d.title AS doctorTitle, dep.name AS doctorDepartment, d.avatar AS doctorAvatar, d.intro AS doctorIntro, dis.name AS diseaseName, dis.alias AS diseaseAlias, dis.description AS diseaseDesc FROM t_follow f LEFT JOIN t_hospital h ON f.follow_type = 1 AND f.follow_id = h.id LEFT JOIN t_doctor d ON f.follow_type = 2 AND f.follow_id = d.id LEFT JOIN t_department dep ON d.department_id = dep.id LEFT JOIN t_disease dis ON f.follow_type = 3 AND f.follow_id = dis.id WHERE f.user_id = #{userId}
AND f.follow_type = #{followType}
ORDER BY f.create_time DESC
